// // This module implements a 4-bit synchronous down counter with a negative edge triggered clock, an active low synchronous reset, and a clear signal.
module up_counter_4bit (
    input clk,
    input reset,
    input load,
    input [3:0] load_value,
    output reg [3:0] q);

always @(posedge clk) begin
    if (reset)
        q <= 4'b0000;
    else if (load)
        q <= load_value;
    else
        q <= q + 1;
    end

endmodule
